class Solution {
    public int smallestValue(int n) {
        int res = n;
        while (true) {
            boolean[] isPrime = new boolean[n + 1];
            Arrays.fill(isPrime, true);
            isPrime[0] = isPrime[1] = false;
            for (int i = 2; i * i <= n; i++) {
                if (isPrime[i]) {
                    for (int j = i * i; j <= n; j += i) {
                        isPrime[j] = false;
                    }
                }
            }
            int sum = 0;
            for (int i = 2; i <= n; i++) {
                if (isPrime[i]) {
                    sum += n / i * i;
                }
            }
            if (sum == res) {
                break;
            }
            res = sum;
            n = sum;
        }
        return res;
    }
}
